# 74HC595 - animierte Visualisierung mit Pygame Zero / pgzero
# Starten mit:
#     python 74hc595_pgzero_animation.py
# oder:
#     pgzrun 74hc595_pgzero_animation.py
#
# Bedienung:
#     LEERTASTE  -> nächstes Datenbit einschieben (SH_CP)
#     L          -> Latch übernehmen (ST_CP)
#     R          -> Reset
#     A          -> Auto-Modus ein/aus
#     O          -> OE umschalten
#
# Voraussetzung:
#     pip install pgzero pygame

import base64
import io
import pygame
import pgzrun

WIDTH = 980
HEIGHT = 610
TITLE = "74HC595 - animiertes Schieberegister"

# Das hochgeladene Logikdiagramm ist direkt im Programm eingebettet.
BILD_B64 = """

"""


class Leitung:
    """Eine sichtbare Verbindungsleitung im Bild."""

    def __init__(self, name, punkte, value=0, color_on=(220, 30, 30), color_off=(145, 145, 145), width=4):
        self.name = name
        self.punkte = punkte
        self.value = value
        self.color_on = color_on
        self.color_off = color_off
        self.width = width

    def set(self, value):
        self.value = 1 if value else 0

    def draw(self, surf, ox=0, oy=0):
        farbe = self.color_on if self.value else self.color_off
        pts = [(x + ox, y + oy) for x, y in self.punkte]
        if len(pts) >= 2:
            pygame.draw.lines(surf, farbe, False, pts, self.width)
        for x, y in pts:
            pygame.draw.circle(surf, farbe, (int(x), int(y)), max(2, self.width // 2))


class HC595:
    """Logikmodell des 74HC595 für die Animation."""

    def __init__(self):
        self.shift = [0] * 8      # internes Schieberegister: QA ... QH
        self.store = [0] * 8      # Ausgangsregister: QA ... QH
        self.ds = 0
        self.oe = 0               # OE = 0 bedeutet: Ausgänge aktiv
        self.mr = 1               # MR = 1 normaler Betrieb
        self.qh_strich = 0        # serieller Ausgang zur Kaskadierung

    def clear(self):
        self.shift = [0] * 8
        self.store = [0] * 8
        self.ds = 0
        self.qh_strich = 0
        self.oe = 0
        self.mr = 1

    def shift_clock(self):
        """Steigende Flanke an SH_CP / SCK."""
        self.qh_strich = self.shift[7]
        for i in range(7, 0, -1):
            self.shift[i] = self.shift[i - 1]
        self.shift[0] = self.ds

    def latch_clock(self):
        """Steigende Flanke an ST_CP / RCK."""
        self.store = self.shift[:]


hc = HC595()
datenfolge = [1, 0, 1, 1, 0, 0, 1, 0]
daten_index = 0

auto = False
auto_timer = 0.0
pulse_sh = 0.0
pulse_st = 0.0
move_timer = 0.0
meldung = "LEERTASTE: schieben   L: latch   R: reset   A: auto   O: OE"

_bg = None
bild_ox = 20
bild_oy = 20

# Ungefähr passende Koordinaten zum eingebetteten Logikdiagramm.
# Die Anzeige unten ist bewusst zusätzlich groß und sauber gezeichnet.
sr_pos = [(177 + i * 55, 88) for i in range(8)]
st_pos = [(196 + i * 55, 178) for i in range(8)]
out_pos = [(213 + i * 55, 260) for i in range(8)]

# Alle wichtigen Verbindungsleiter als Objekte.
leitungen = {}
leitungen["SI / DS"] = Leitung("SI / DS", [(58, 72), (135, 72)], color_on=(230, 20, 20))
leitungen["SCK / SH_CP"] = Leitung("SCK / SH_CP", [(58, 117), (135, 117)], color_on=(20, 80, 220))
leitungen["RCK / ST_CP"] = Leitung("RCK / ST_CP", [(58, 202), (155, 202)], color_on=(20, 150, 40))
leitungen["OE"] = Leitung("OE", [(58, 252), (160, 252)], color_on=(130, 0, 160))
leitungen["MR / SCLR"] = Leitung("MR / SCLR", [(58, 33), (135, 33)], color_on=(20, 150, 40))
leitungen["QH'"] = Leitung("QH'", [(590, 72), (650, 72)], color_on=(230, 20, 20))

for i in range(8):
    leitungen[f"SR{i}"] = Leitung(
        f"SR{i}",
        [(sr_pos[i][0] - 18, sr_pos[i][1]), (sr_pos[i][0] + 18, sr_pos[i][1])],
        color_on=(230, 20, 20),
        width=5,
    )
    leitungen[f"Latch{i}"] = Leitung(
        f"Latch{i}",
        [(sr_pos[i][0], 112), (st_pos[i][0], 158)],
        color_on=(20, 150, 40),
        width=4,
    )
    leitungen[f"Q{i}"] = Leitung(
        f"Q{i}",
        [(st_pos[i][0], 196), (out_pos[i][0], 244)],
        color_on=(230, 20, 20),
        width=4,
    )


def naechstes_bit_schieben():
    global daten_index, pulse_sh, move_timer, meldung

    if daten_index >= len(datenfolge):
        meldung = "Alle 8 Bits sind eingeschoben. Jetzt L für Latch drücken."
        return

    hc.ds = datenfolge[daten_index]
    hc.shift_clock()
    daten_index += 1
    pulse_sh = 0.22
    move_timer = 0.40
    meldung = f"SH_CP: Bit {hc.ds} eingeschoben  ({daten_index}/8)"


def latch_uebernehmen():
    global pulse_st, meldung
    hc.latch_clock()
    pulse_st = 0.35
    meldung = "ST_CP: Alle 8 Bits gleichzeitig ins Ausgangsregister übernommen."


def reset():
    global daten_index, pulse_sh, pulse_st, move_timer, meldung
    hc.clear()
    daten_index = 0
    pulse_sh = 0
    pulse_st = 0
    move_timer = 0
    meldung = "Reset: Schiebe- und Ausgangsregister gelöscht."


def on_key_down(key):
    global auto, meldung
    if key == keys.SPACE:
        naechstes_bit_schieben()
    elif key == keys.L:
        latch_uebernehmen()
    elif key == keys.R:
        reset()
    elif key == keys.A:
        auto = not auto
        meldung = "Auto-Modus EIN" if auto else "Auto-Modus AUS"
    elif key == keys.O:
        hc.oe = 1 - hc.oe
        meldung = "OE = 0: Ausgänge aktiv" if hc.oe == 0 else "OE = 1: Ausgänge hochohmig / deaktiviert"


def update(dt):
    global pulse_sh, pulse_st, move_timer, auto_timer, auto
    pulse_sh = max(0, pulse_sh - dt)
    pulse_st = max(0, pulse_st - dt)
    move_timer = max(0, move_timer - dt)

    if auto:
        auto_timer += dt
        if auto_timer > 0.85:
            auto_timer = 0
            if daten_index < len(datenfolge):
                naechstes_bit_schieben()
            else:
                latch_uebernehmen()
                auto = False


def lade_hintergrund():
    global _bg
    if _bg is None:
        raw = base64.b64decode(BILD_B64)
        _bg = pygame.image.load(io.BytesIO(raw)).convert_alpha()
    return _bg


def text_box(text, x, y, w, h, color=(245, 245, 245), border=(40, 40, 40)):
    pygame.draw.rect(screen.surface, color, (x, y, w, h), border_radius=8)
    pygame.draw.rect(screen.surface, border, (x, y, w, h), 2, border_radius=8)
    screen.draw.text(text, (x + 10, y + 8), color="black", fontsize=22)


def zeichne_bit(x, y, value, label=None, active=False):
    farbe = (245, 80, 80) if value else (230, 230, 230)
    rand = (220, 20, 20) if value else (100, 100, 100)
    if active:
        rand = (20, 80, 230)
    pygame.draw.rect(screen.surface, farbe, (x - 15, y - 15, 30, 30), border_radius=5)
    pygame.draw.rect(screen.surface, rand, (x - 15, y - 15, 30, 30), 3, border_radius=5)
    screen.draw.text(str(value), center=(x, y - 1), color="black", fontsize=24)
    if label:
        screen.draw.text(label, center=(x, y + 28), color="black", fontsize=15)


def zeichne_led(x, y, value):
    if hc.oe == 1:
        color = (170, 170, 170)
    else:
        color = (235, 30, 30) if value else (180, 180, 180)
    pygame.draw.circle(screen.surface, color, (x, y), 13)
    pygame.draw.circle(screen.surface, (40, 40, 40), (x, y), 13, 2)
    if value and hc.oe == 0:
        for dx, dy in [(-20, 0), (20, 0), (0, -20), (-14, -14), (14, -14)]:
            pygame.draw.line(screen.surface, (235, 30, 30), (x, y), (x + dx, y + dy), 2)


def aktualisiere_leitungen():
    leitungen["SI / DS"].set(hc.ds)
    leitungen["SCK / SH_CP"].set(1 if pulse_sh > 0 else 0)
    leitungen["RCK / ST_CP"].set(1 if pulse_st > 0 else 0)
    leitungen["OE"].set(0 if hc.oe else 1)
    leitungen["MR / SCLR"].set(hc.mr)
    leitungen["QH'"].set(hc.qh_strich)
    for i in range(8):
        leitungen[f"SR{i}"].set(hc.shift[i])
        leitungen[f"Latch{i}"].set(1 if pulse_st > 0 and hc.shift[i] else 0)
        leitungen[f"Q{i}"].set(hc.store[i] if hc.oe == 0 else 0)


def draw():
    screen.clear()
    screen.fill((252, 252, 252))

    bg = lade_hintergrund()
    screen.surface.blit(bg, (bild_ox, bild_oy))

    aktualisiere_leitungen()
    for leitung in leitungen.values():
        leitung.draw(screen.surface, bild_ox, bild_oy)

    # Overlay-Bits direkt auf dem Datenblattbild
    for i, value in enumerate(hc.shift):
        x, y = sr_pos[i]
        zeichne_bit(x + bild_ox, y + bild_oy, value, active=(pulse_sh > 0))

    for i, value in enumerate(hc.store):
        x, y = st_pos[i]
        zeichne_bit(x + bild_ox, y + bild_oy, value, active=(pulse_st > 0))

    # LEDs / Ausgänge im Originalbild hervorheben
    for i, value in enumerate(hc.store):
        x, y = out_pos[i]
        zeichne_led(x + bild_ox, y + bild_oy + 35, value)

    # wanderndes Datenbit als bewegter Punkt
    if move_timer > 0:
        p = 1.0 - move_timer / 0.40
        x0, y0 = bild_ox + 60, bild_oy + 72
        x1, y1 = bild_ox + sr_pos[0][0], bild_oy + sr_pos[0][1]
        x = x0 + (x1 - x0) * p
        y = y0 + (y1 - y0) * p
        pygame.draw.circle(screen.surface, (255, 120, 0), (int(x), int(y)), 12)
        screen.draw.text(str(hc.ds), center=(x, y), color="black", fontsize=20)

    # Bedien- und Erklärbereich unten
    y0 = 385
    text_box("74HC595-Testanimation", 20, y0, 940, 45, color=(235, 245, 255), border=(20, 80, 180))
    screen.draw.text(meldung, (40, y0 + 55), color="black", fontsize=24)

    screen.draw.text("Datenfolge:", (40, y0 + 95), color="black", fontsize=24)
    for i, bit in enumerate(datenfolge):
        x = 175 + i * 42
        active = (i == daten_index)
        zeichne_bit(x, y0 + 108, bit, active=active)

    screen.draw.text("Schieberegister  QA ... QH", (40, y0 + 155), color="blue", fontsize=24)
    for i, bit in enumerate(hc.shift):
        zeichne_bit(260 + i * 42, y0 + 168, bit, label=f"Q{chr(65+i)}")

    screen.draw.text("Ausgangsregister QA ... QH", (40, y0 + 215), color="darkgreen", fontsize=24)
    for i, bit in enumerate(hc.store):
        zeichne_bit(260 + i * 42, y0 + 228, bit, label=f"Q{chr(65+i)}")

    screen.draw.text("rot = 1 / aktiv", (740, y0 + 95), color="red", fontsize=22)
    screen.draw.text("grau = 0", (740, y0 + 125), color="gray", fontsize=22)
    screen.draw.text("blau = SH_CP", (740, y0 + 155), color="blue", fontsize=22)
    screen.draw.text("grün = ST_CP / Latch", (740, y0 + 185), color="darkgreen", fontsize=22)
    screen.draw.text(f"OE = {hc.oe}", (740, y0 + 215), color="purple", fontsize=22)


pgzrun.go()
